const body = $json.body ?? $json;

const type = String(body.type || '').trim().toLowerCase();
const text = String(body.text || '').trim();
const source_name = String(body.source_name || 'manual input').trim();
const user_id = String(body.user_id || 'default-user').trim();

// Update: wedding_savings instead of money_saving
if (!['expense', 'wedding_savings'].includes(type)) {
  throw new Error('type harus expense atau wedding_savings');
}

if (!text) {
  throw new Error('text wajib diisi');
}

return [{ json: { type, text, source_name, user_id } }];

const raw = $json.choices?.[0]?.message?.content || '{}';

let text = String(raw).trim();
const start = text.indexOf('{');
const end = text.lastIndexOf('}');
if (start !== -1 && end !== -1 && end > start) {
  text = text.slice(start, end + 1);
}

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  return [{
    json: {
      success: false,
      error: 'Gagal parse JSON dari AI',
      raw_response: raw
    }
  }];
}

const inputData = $('Validate Input').first().json;

return [{
  json: {
    success: true,
    user_id: inputData.user_id,
    source_name: inputData.source_name,
    raw_text: inputData.text,
    raw_ai_response: JSON.stringify(parsed),
    data: parsed
  }
}];

// Get data from previous nodes
const sheetData = $json;
const parseNode = $('Parse AI Response').first().json;

// Parse AI response from Sheets
const aiData = parseNode.data;

// Transform to app format
return [{
  json: {
    user_id: sheetData.user_id || parseNode.user_id,
    source_name: sheetData.source_name || parseNode.source_name,
    sheets_row: sheetData.row_number,
    transaction: {
      type: aiData.type,
      total: Number(aiData.total) || 0,
      merchant: aiData.merchant || '',
      category: aiData.category || '',
      payment_method: aiData.payment_method || '',
      transaction_date: aiData.transaction_date || new Date().toISOString().split('T')[0],
      notes: aiData.notes || ''
    }
  }
}];

return [{
  json: {
    model: "deepseek-chat",
    messages: [
      {
        role: "user",
        content: $json.prompt
      }
    ],
    temperature: 0.2
  }
}];

return [{
  json: {
    user_id: $json.user_id,
    type: $json.transaction.type,
    source_name: $json.source_name,
    transaction_date: $json.transaction.transaction_date,
    merchant: $json.transaction.merchant,
    category: $json.transaction.category,
    payment_method: $json.transaction.payment_method,
    total: $json.transaction.total,
    notes: $json.transaction.notes,
    sheets_row_id: $json.sheets_row,
  },
}];

const transformed = $('Transform to App Format').first().json;
const supabaseResponse = $('Save to Supabase').first().json;
const insertedRow = Array.isArray(supabaseResponse) ? supabaseResponse[0] : supabaseResponse;

return [{
  json: {
    success: true,
    source_name: transformed.source_name,
    data: transformed.transaction,
    sheets_row: transformed.sheets_row,
    db_id: insertedRow?.id ?? null,
  },
}];

