// Loop over input items and add a new field called 'myNewField' to the JSON of each one
// file: n8n_code_mask_sensitive.js
// Node: Code (JavaScript)
// Input: Ambil dari node "Image to Text" dengan properti json.text (sesuaikan jika lain)
// Output: Dua items:
//   - items[0].json -> data[1]: { nik, nama }
//   - items[1].json -> data[2]: { maskedText, originalText, nikMaskedExample, namaMaskedExample }
//
// Catatan:
// - Regex dibuat toleran variasi OCR: tanda sama dengan, dash, garis, spasi ganda,
//   dan karakter non-alfanumerik di sekitar label.
// - Masking dilakukan mengganti semua kemunculan NIK/Nama di teks penuh dengan bintang (*).
// - Jika NIK/Nama tidak ditemukan, tetap keluarkan struktur standar (nik/nama null) dan teks tidak diubah.
// - Pastikan node “Image to Text” benar-benar mengoutput field "text". Jika berbeda, ubah `sourceText` assignment di bawah.

// file: n8n_code_structured_output.js
// Node: Code (JavaScript)
// Input: item[0].json.text dari node "Image to Text"
// Output: Satu item dengan struktur:
// {
//   meta: { sourceNode, processedAt },
//   data: {
//     1: { nik, nama },
//     2: { originalText, maskedText, masked: { nik, nama } }
//   }
// }

function cleanDecorations(str) {
  if (!str) return '';
  return str
    .replace(/[“”"’‘]/g, '"')
    .replace(/[—–‐\-]+/g, '-') // normalisasi dash
    .replace(/[=_]+/g, '=')    // normalisasi '='
    .replace(/\u00A0/g, ' ')
    .trim();
}

function normalizeSpaces(str) {
  return str.replace(/[ \t]+/g, ' ').replace(/\r/g, '').replace(/\n{3,}/g, '\n\n');
}

function extractNik(text) {
  const nikLabel = /(?:\bNIK\b)\s*(?:[:=]|\-)?\s*([0-9]{8,20})/i;
  const m = text.match(nikLabel);
  return m ? m[1] : null;
}

function extractNama(text) {
  const lines = text.split('\n');
  let candidate = null;
  for (const line of lines) {
    const cl = cleanDecorations(line);
    if (/^\s*Nama\b/i.test(cl)) {
      const after = cl.replace(/^\s*Nama\b\s*(?:[:=]|\-+)?\s*/i, '');
      candidate = after;
      break;
    }
  }
  if (!candidate) {
    const namaLabel = /(?:\bNama\b)\s*(?:[:=]|\-+)?\s*("?)([A-ZÁ-ÚÀ-ÙÄ-Üa-zá-úà-ùä-ü.'\s]{2,})\1(?=$|\n)/i;
    const m = text.match(namaLabel);
    if (m) candidate = m[2];
  }
  if (!candidate) return null;

  candidate = candidate
    .replace(/[:\-"]+$/g, '')
    .replace(/\s{2,}/g, ' ')
    .trim();

  candidate = candidate.replace(/\b(Tempat|Tanggal|Tempat\/|Jenis|Alamat|RT|RW|Kel|Desa|Kecamatan|Agama|Status|Perkawinan|Pekerjaan|Kewarganegaraan|Berlaku)\b.*$/i, '').trim();
  candidate = candidate.replace(/[^\w\s.'-]+$/g, '').trim();

  if (!candidate || candidate.length < 2) return null;
  return candidate;
}

function maskExact(haystack, secret) {
  if (!secret || !haystack) return haystack;
  const escaped = secret.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const mask = '*'.repeat(secret.length);
  return haystack.replace(new RegExp(escaped, 'g'), mask);
}

function maskNameByWords(haystack, name) {
  if (!name || !haystack) return haystack;
  const words = name.split(/\s+/).filter(w => w.length >= 3);
  let result = haystack;
  for (const w of words) {
    const escaped = w.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const mask = '*'.repeat(w.length);
    result = result.replace(new RegExp(escaped, 'gi'), mask);
  }
  return result;
}

function main(items) {
  const inputItem = items[0] || {};
  const inputText = (inputItem.json && inputItem.json.text) || '';
  const originalText = String(inputText || '');

  const working = normalizeSpaces(cleanDecorations(originalText));

  const nik = extractNik(working);
  const nama = extractNama(working);

  let maskedText = originalText;
  if (nik) maskedText = maskExact(maskedText, nik);
  if (nama) maskedText = maskNameByWords(maskedText, nama);

  const output = {
    meta: {
      sourceNode: 'Image to Text',
      processedAt: new Date().toISOString()
    },
    data: {
      1: {
        nik: nik || null,
        nama: nama || null
      },
      2: {
        originalText,
        maskedText,
        masked: {
          nik: nik ? '*'.repeat(nik.length) : null,
          nama: nama
            ? nama
                .split(/\s+/)
                .map(w => (w.length >= 3 ? '*'.repeat(w.length) : w))
                .join(' ')
            : null
        }
      }
    }
  };

  return [{ json: output }];
}

return main($input.all())[0].json.data;
